"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[411],{852:e=>{e.exports=JSON.parse('{"label":"pwn","permalink":"/docs/tags/pwn","allTagsPath":"/docs/tags","count":3,"items":[{"id":"ctf-writeups/2023/picoctf/babygame01","title":"babygame01 - picoCTF 2023","description":"Hello fellow hackers! Today we are attempting the babygame01 challenge from picoCTF 2023. This is a binary exploitation challenge that involves underflowing a buffer to modify a value on the stack to satisfy the condition of an if statement.","permalink":"/docs/ctf-writeups/2023/picoctf/babygame01"},{"id":"ctf-writeups/2023/hackasat-qualifier/riscv-smash-baby","title":"RISC-V Smash Baby - Hack-A-Sat Qualifier 2023","description":"Hello fellow hackers! Today we\'re attempting to solve the RISC-V Smash Baby challenge from the Pure Pwnage category of Hack-A-Sat Qualifier 2023 CTF. The program first leaks the memory address where the flag is stored on the main function stack and stores the flag to disk. A function vulnerable to buffer overflow can be reached by satisfying some value checks. Hence, the flag can be obtained by uploading shellcode that will print the string located at the leaked memory address, or by spawning a shell and printing the flag.","permalink":"/docs/ctf-writeups/2023/hackasat-qualifier/riscv-smash-baby"},{"id":"ctf-writeups/2022/picoctf/ropfu","title":"ropfu - picoCTF 2022","description":"Hello fellow hackers! Today we are attempting to solve the ropfu challenge from picoCTF 2022. This challenge consists in exploiting a buffer overflow vulnerability using Return Oriented Programming to spawn a shell.","permalink":"/docs/ctf-writeups/2022/picoctf/ropfu"}],"unlisted":false}')}}]);